class SensitiveDataFilter(logging.Filter):
    """
    A logging filter that redacts sensitive information from log messages.
    This prevents accidental exposure of passwords, tokens, API keys, etc.
    """

    SENSITIVE_PATTERNS = [
        # Passwords in various formats
        (re.compile(r'(password["\s:=]+)[^\s,}"\']+', re.IGNORECASE), r'\1[REDACTED]'),
        (re.compile(r'(passwd["\s:=]+)[^\s,}"\']+', re.IGNORECASE), r'\1[REDACTED]'),
        (re.compile(r'(pwd["\s:=]+)[^\s,}"\']+', re.IGNORECASE), r'\1[REDACTED]'),
        # Auth tokens and API keys
        (re.compile(r'(token["\s:=]+)[^\s,}"\']+', re.IGNORECASE), r'\1[REDACTED]'),
        (re.compile(r'(api[_-]?key["\s:=]+)[^\s,}"\']+', re.IGNORECASE), r'\1[REDACTED]'),
        (re.compile(r'(secret["\s:=]+)[^\s,}"\']+', re.IGNORECASE), r'\1[REDACTED]'),
        (re.compile(r'(authorization["\s:=]+)\S+', re.IGNORECASE), r'\1[REDACTED]'),
        # Bearer tokens
        (re.compile(r'(Bearer\s+)\S+', re.IGNORECASE), r'\1[REDACTED]'),
        # Credit card numbers (basic pattern)
        (re.compile(r'\b(\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?)\d{4}\b'), r'\1****'),
        # SSN patterns
        (re.compile(r'\b(\d{3}[-\s]?\d{2}[-\s]?)\d{4}\b'), r'\1****'),
        # Session IDs
        (re.compile(r'(session[_-]?id["\s:=]+)[^\s,}"\']+', re.IGNORECASE), r'\1[REDACTED]'),
        # Cookie values (redact full cookie strings)
        (re.compile(r'(cookie["\s:=]+)[^\n]+', re.IGNORECASE), r'\1[REDACTED]'),
    ]

    def filter(self, record):
        """Apply redaction patterns to the log message."""
        if isinstance(record.msg, str):
            record.msg = self._redact(record.msg)
        if record.args:
            record.args = tuple(
                self._redact(str(arg)) if isinstance(arg, str) else arg
                for arg in record.args
            )
        return True

    def _redact(self, message):
        """Apply all redaction patterns to a message string."""
        for pattern, replacement in self.SENSITIVE_PATTERNS:
            message = pattern.sub(replacement, message)
        return message


def sanitize_dict(data, sensitive_keys=None):
    """
    Recursively sanitize a dictionary by redacting values of sensitive keys.
    Returns a new dictionary safe for logging.
    """
    if sensitive_keys is None:
        sensitive_keys = {
            'password', 'passwd', 'pwd', 'token', 'access_token',
            'refresh_token', 'api_key', 'apikey', 'secret', 'secret_key',
            'authorization', 'auth_token', 'session_id', 'sessionid',
            'cookie', 'cookies', 'credit_card', 'card_number', 'cvv',
            'ssn', 'social_security', 'private_key',
        }

    if not isinstance(data, dict):
        return data

    sanitized = {}
    for key, value in data.items():
        key_lower = key.lower().replace('-', '_')
        if key_lower in sensitive_keys:
            sanitized[key] = '[REDACTED]'
        elif isinstance(value, dict):
            sanitized[key] = sanitize_dict(value, sensitive_keys)
        elif isinstance(value, list):
            sanitized[key] = [
                sanitize_dict(item, sensitive_keys) if isinstance(item, dict) else item
                for item in value
            ]
        else:
            sanitized[key] = value
    return sanitized


def sanitize_headers(headers):
    """
    Sanitize HTTP headers for safe logging.
    Redacts Authorization, Cookie, and other sensitive headers.
    """
    sensitive_headers = {
        'authorization', 'cookie', 'set-cookie', 'x-api-key',
        'x-auth-token', 'proxy-authorization', 'x-csrf-token',
    }
    sanitized = {}
    for key, value in headers:
        if key.lower() in sensitive_headers:
            sanitized[key] = '[REDACTED]'
        else:
            sanitized[key] = value
    return sanitized


