# Simple token store (in production, use JWT or a proper session store)
ACTIVE_TOKENS = {}


def generate_token(username):
    """Generate a secure random token for a user session."""
    token = secrets.token_urlsafe(32)
    ACTIVE_TOKENS[token] = {
        'username': username,
        'created': datetime.utcnow(),
        'expires': datetime.utcnow() + timedelta(hours=1),
    }
    return token


def verify_token(token):
    """Verify a token and return the associated username, or None."""
    session = ACTIVE_TOKENS.get(token)
    if session and session['expires'] > datetime.utcnow():
        return session['username']
    if session:
        # Token expired, clean up
        del ACTIVE_TOKENS[token]
    return None


def token_to_fingerprint(token):
    """
    Create a non-reversible fingerprint of a token for logging purposes.
    This allows correlating log entries without exposing the actual token.
    """
    if not token:
        return 'none'
    return hashlib.sha256(token.encode()).hexdigest()[:12]


def require_auth(f):
    """Decorator to require authentication for an endpoint."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        token = None

        if auth_header.startswith('Bearer '):
            token = auth_header[7:]

        if not token:
            logger.warning(
                "Unauthenticated request to %s from %s - no token provided",
                request.path, request.remote_addr
            )
            return jsonify({'error': 'Authentication required'}), 401

        username = verify_token(token)
        if not username:
            # Log token fingerprint (NOT the actual token) for debugging
            logger.warning(
                "Invalid/expired token used for %s from %s | token_fingerprint=%s",
                request.path, request.remote_addr, token_to_fingerprint(token)
            )
            return jsonify({'error': 'Invalid or expired token'}), 401

        g.current_user = username
        g.token_fingerprint = token_to_fingerprint(token)
        return f(*args, **kwargs)
    return decorated


