@app.route('/api/login', methods=['POST'])
def login():
    """
    Authenticate a user and return a session token.

    NOTE: We intentionally do NOT log the password or the generated token.
    We log only the username and whether the attempt succeeded or failed.
    """
    data = request.get_json(silent=True) or {}
    username = data.get('username', '')
    password = data.get('password', '')

    # Log the login attempt WITHOUT the password
    logger.info(
        "LOGIN ATTEMPT | user=%s | remote_addr=%s",
        username, request.remote_addr
    )

    if not username or not password:
        logger.warning(
            "LOGIN FAILED | user=%s | reason=missing_credentials | remote_addr=%s",
            username, request.remote_addr
        )
        return jsonify({'error': 'Username and password are required'}), 400

    user = USERS.get(username)
    if not user:
        logger.warning(
            "LOGIN FAILED | user=%s | reason=user_not_found | remote_addr=%s",
            username, request.remote_addr
        )
        # Use generic error message to prevent user enumeration
        return jsonify({'error': 'Invalid credentials'}), 401

    password_hash = hashlib.sha256(password.encode()).hexdigest()
    if password_hash != user['password_hash']:
        logger.warning(
            "LOGIN FAILED | user=%s | reason=invalid_password | remote_addr=%s",
            username, request.remote_addr
        )
        return jsonify({'error': 'Invalid credentials'}), 401

    token = generate_token(username)
    token_fp = token_to_fingerprint(token)

    # Log success with token fingerprint (NOT the actual token)
    logger.info(
        "LOGIN SUCCESS | user=%s | role=%s | token_fingerprint=%s | remote_addr=%s",
        username, user['role'], token_fp, request.remote_addr
    )

    return jsonify({
        'message': 'Login successful',
        'token': token,
        'username': username,
        'role': user['role'],
    })


